/**
 * Generated by scripts/parse-am4edit-labels.ts. Do not hand-edit.
 *
 * Source: AM4-Edit.exe embedded JUCE BinaryData ZIP.
 *   __block_layout.xml         — first-page knobs
 *   __block_layout_expert.xml  — expert/advanced-page knobs
 *   __components.xml           — non-block UI elements
 *
 * The mapping is keyed by AM4-Edit's symbolic parameter ID
 * (e.g. DISTORT_TREBLE). Each entry has:
 *   - canonicalLabel: the display name used by the AM4-Edit UI
 *     (most-common across contexts; ties resolved to the first-page label).
 *   - contexts: every place this parameterName appears, with the
 *     label used in that context. Use the context-matched label when
 *     a tool surface knows the active block (DISTORT_TREBLE shows as
 *     "Treble" on amp, "Tone" on drive).
 */

