export const EDITOR_CONTROL_PARAMETER_NAMES = Object.keys(EDITOR_CONTROLS);

/**
 * Resolve the AM4-Edit display label for a parameterName, optionally
 * preferring the label used in a specific block/page context.
 *
 * Returns the canonical label when no context match is found, or
 * undefined if the parameterName is unknown.
 */
export function resolveEditorControlLabel(
    parameterName: string,
    context?: { block?: string; pageLayer?: string },
): string | undefined {
    const entry = EDITOR_CONTROLS[parameterName];
    if (!entry) return undefined;
    if (!context) return entry.canonicalLabel;

    // Filter contexts by the requested block / pageLayer, then
    // return the MOST-COMMON label within the filtered set. This
    // matters for blocks like Amp where different amp variants
    // use different labels for the same wire param (e.g. simple
    // amps show "Tone", standard amps show "Treble" for
    // DISTORT_TREBLE).
    const filtered = entry.contexts.filter(c => {
        if (context.block && c.block !== context.block) return false;
        if (context.pageLayer && c.pageLayer !== context.pageLayer) return false;
        return true;
    });
    if (filtered.length === 0) return entry.canonicalLabel;
    const counts = new Map<string, number>();
    for (const c of filtered) counts.set(c.label, (counts.get(c.label) ?? 0) + 1);
    let bestLabel = filtered[0].label;
    let bestCount = 0;
    for (const [l, n] of counts) {
        if (n > bestCount) { bestCount = n; bestLabel = l; }
    }
    return bestLabel;
}
